create table if not exists public.question_bank (
  id integer generated by default as identity primary key,
  question text not null,
  options text[] not null check (array_length(options, 1) = 4),
  correct_answer smallint not null check (correct_answer between 0 and 3),
  verse text not null,
  active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.question_bank enable row level security;

drop policy if exists "question_bank_select_public" on public.question_bank;
create policy "question_bank_select_public"
  on public.question_bank
  for select
  to anon, authenticated
  using (active = true);

create or replace function public.update_question_bank_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

drop trigger if exists trg_question_bank_updated_at on public.question_bank;
create trigger trg_question_bank_updated_at
before update on public.question_bank
for each row execute function public.update_question_bank_updated_at();

insert into public.question_bank (id, question, options, correct_answer, verse, active)
values
